                    }
                    resourceId = new ResourceIdentifier(prop.Value.GetString());
                    continue;
                }
                if (prop.NameEquals("metricsProfile"u8))
                {
                    if (prop.Value.ValueKind == JsonValueKind.Null)
                    {
                        continue;
                    }
                    metricsProfile = ManagedClusterMetricsProfile.DeserializeManagedClusterMetricsProfile(prop.Value, options);
                    continue;
                }
                if (prop.NameEquals("nodeProvisioningProfile"u8))
                {
                    if (prop.Value.ValueKind == JsonValueKind.Null)
                    {
                        continue;
                    }
                    nodeProvisioningProfile = ManagedClusterNodeProvisioningProfile.DeserializeManagedClusterNodeProvisioningProfile(prop.Value, options);
                    continue;
                }
                if (prop.NameEquals("bootstrapProfile"u8))
                {
                    if (prop.Value.ValueKind == JsonValueKind.Null)
                    {
                        continue;
                    }
                    bootstrapProfile = ManagedClusterBootstrapProfile.DeserializeManagedClusterBootstrapProfile(prop.Value, options);
                    continue;
                }
                if (prop.NameEquals("aiToolchainOperatorProfile"u8))
                {
                    if (prop.Value.ValueKind == JsonValueKind.Null)
                    {
                        continue;
                    }
                    aiToolchainOperatorProfile = ManagedClusterAIToolchainOperatorProfile.DeserializeManagedClusterAIToolchainOperatorProfile(prop.Value, options);
                    continue;
                }
                if (prop.NameEquals("status"u8))
                {
                    if (prop.Value.ValueKind == JsonValueKind.Null)
                    {
                        continue;
                    }
                    status = ManagedClusterStatus.DeserializeManagedClusterStatus(prop.Value, options);
                    continue;
                }
                if (options.Format != "W")
                {
                    additionalBinaryDataProperties.Add(prop.Name, BinaryData.FromString(prop.Value.GetRawText()));
                }
            }
            return new ManagedClusterProperties(
                provisioningState,
                powerState,
                maxAgentPools,
                kubernetesVersion,
                currentKubernetesVersion,
                dnsPrefix,
                fqdnSubdomain,
                fqdn,
                privateFqdn,
                azurePortalFqdn,
                agentPoolProfiles ?? new ChangeTrackingList<ManagedClusterAgentPoolProfile>(),
                linuxProfile,
                windowsProfile,
                servicePrincipalProfile,
                addonProfiles ?? new ChangeTrackingDictionary<string, ManagedClusterAddonProfile>(),
                podIdentityProfile,
                oidcIssuerProfile,
                nodeResourceGroup,
                nodeResourceGroupProfile,
                isRbacEnabled,
                supportPlan,
                networkProfile,
                aadProfile,
                autoUpgradeProfile,
                upgradeSettings,
                autoScalerProfile,
                apiServerAccessProfile,
                diskEncryptionSetId,
                identityProfile ?? new ChangeTrackingDictionary<string, ContainerServiceUserAssignedIdentity>(),
                privateLinkResources ?? new ChangeTrackingList<ContainerServicePrivateLinkResourceData>(),
                isLocalAccountsDisabled,
                httpProxyConfig,
                securityProfile,
                storageProfile,
                ingressProfile,
                publicNetworkAccess,
                workloadAutoScalerProfile,
                azureMonitorProfile,
                serviceMeshProfile,
                resourceId,
                metricsProfile,
                nodeProvisioningProfile,
                bootstrapProfile,
                aiToolchainOperatorProfile,
                status,
                additionalBinaryDataProperties);
        }
    }
